#!/usr/bin/env python3
"""
mkt-original commentary -- Lamentations 1-2 (44 verses)
Run: python3 scripts/zc-original-lamentations-1-2-full.py

Lamentations (Hebrew: Eikha -- 'How!') consists of five acrostic poems
mourning the destruction of Jerusalem in 586 BCE.

Chs 1-2 are both 22-verse aleph-bet acrostics (each verse begins with the
next letter of the Hebrew alphabet). Ch 2 reverses the ayin-pe order compared
to ch 1 (a textual variant reflected in some manuscripts).

Key Hebrew terms:
  eikhah (H349) -- the opening lamentation particle 'How!' (= the book's name)
  Bat-Tzion (Daughter Zion) -- Jerusalem personified as a grieving woman
  menachem (H5162, comforter) -- absent throughout ch 1; the dominant negative
  qinah -- the 3+2 dirge meter that 'limps' through grief
  me'en-nachem (none to comfort) -- the refrain of ch 1
  oni (H6040) -- affliction, misery
  pesha (H6588) -- transgression, the covenant-breaking that caused exile
  avon (H5771) -- iniquity; both the sin and its punishment
  eb (H340) -- enemy; YHWH acts like an eb in ch 2
  moed (H4150) -- appointed feast/assembly; the disrupted liturgy
  galah/galut (H1540/H1473) -- to go into exile; the deportation
  niddah (H5079) -- ritual impurity; Jerusalem's defilement
  midbar (measuring line) -- YHWH's deliberate demolition plan (2:8)
  navi/chazut (prophet/vision) -- false prophets who gave no warning (2:14)
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LAMENTATIONS = {
    "1": {
        "1": "<p><strong>Eikhah yashvah vadad ha-ir</strong> -- 'How the city sits alone!' The book opens with <em>eikhah</em> (H349), the particle of lamentation -- 'How!' or 'Alas!' -- used also in Isa 1:21 ('How the faithful city has become a harlot!') and Jer 48:17. It is also the book's Hebrew name. The word is not a question but an exclamation of grief at reversal: the formerly great city now sits <em>vadad</em> (alone, isolated, desolate). <em>Rabati am hayetah ke-almanah</em> -- 'she who was great among the nations has become like a widow.' The widow (<em>almanah</em>) is the most vulnerable social category in ancient Israel -- without male protection, without status, without provision. Jerusalem's greatness has been stripped down to this condition. The verse initiates the first aleph-bet acrostic (aleph = the first letter).</p>",
        "2": "<p><strong>Bakho tivkeh ba-layil</strong> -- 'She weeps bitterly in the night.' The infinitive absolute <em>bakho</em> before the finite verb <em>tivkeh</em> intensifies: she weeps and weeps, continuously and desperately. <em>Ve-dimatah al lhyah</em> -- 'and her tears are on her cheeks.' The tears flow without being wiped away -- the image of grief so deep it goes unattended. <em>Ein-lah menachem mi-kol-ohaveyha</em> -- 'she has no comforter from all her lovers.' The first occurrence of the <em>menachem</em> (H5162, comforter) refrain that dominates ch 1. The 'lovers' (<em>ohavim</em>) are the political allies -- Egypt, Assyria, the surrounding nations -- who promised protection but have abandoned her. <em>Kol-reyha bagdu vah</em> -- 'all her friends have dealt treacherously with her' -- <em>bagad</em> (to betray/act treacherously), the vocabulary of covenant betrayal.</p>",
        "3": "<p><strong>Galtah Yehudah me-oni u-me-rov avodah</strong> -- 'Judah has gone into exile because of affliction and because of great servitude.' <em>Galah</em> (H1540, to go into exile/uncover) -- the displacement of the covenant people from their land. <em>Oni</em> (H6040, affliction/misery) and <em>avodah</em> (H5656, labor/servitude) are the conditions that drove the exile. <em>Hi yoshevet baggoyim lo matzaah manoach</em> -- 'she dwells among the nations; she finds no resting place.' <em>Manoach</em> (resting place) -- the same word used in Ruth 3:1 for the security of marriage-home; Judah in exile has no such rest. <em>Kol-rodfeha hisiguha bein ha-metzarim</em> -- 'all her pursuers overtook her in the narrow places.' <em>Metzarim</em> (narrow straits/distress) -- also the word for Egypt (<em>Mitzrayim</em>); the exile involves a reversal to Egypt-like bondage.</p>",
        "4": "<p><strong>Darkei Tziyyon avelot</strong> -- 'The roads of Zion mourn.' The personification extends: the roads themselves grieve because no pilgrim traffic moves on them. <em>Mi-bli vai moed</em> -- 'because none come to the appointed feast.' <em>Moed</em> (H4150, appointed time/feast/assembly) -- the great pilgrimage festivals (Passover, Shavuot, Sukkot) that filled the roads with worshippers have ceased. <em>Kol-sharehah shomemot</em> -- 'all her gates are desolate.' <em>Shomemot</em> (desolate/appalled) -- the verb used for the desolation of the Temple in Dan 9:27. <em>Kohanehah neenaichim</em> -- 'her priests groan.' The priests who led the cult now lead the grief. <em>Betulotehah nugot ve-hi mar-lah</em> -- 'her virgins are afflicted and she herself is bitter.' <em>Betulot</em> (young women/virgins) -- the most vulnerable of the population, representing both future hope and present desolation.</p>",
        "5": "<p><strong>Hayu tzarehah le-rosh</strong> -- 'Her enemies have become the head.' <em>Tzarehah</em> (her enemies/adversaries) has inverted the covenant promise of Deut 28:44 -- the covenant curse is that the enemy will be the head and Israel the tail when Israel disobeys. <em>Oyvehah shalu</em> -- 'her foes prosper.' <em>Shavah</em> (to prosper/be at peace) -- the peace that was Israel's covenant gift now belongs to the oppressor. <em>Ki-YHWH hogah al rov-pishaeyha</em> -- 'because YHWH has afflicted her for the abundance of her transgressions.' <em>Hogah</em> (to afflict/grieve, H3013) -- the divine action is named clearly: the enemy's victory is YHWH's instrument. <em>Pishaeyha</em> (her transgressions, H6588) -- covenant violations, not merely moral failures. <em>Olaleyha halekhu shevi lifnei tzar</em> -- 'her children have gone into captivity before the enemy.' The children in exile is the sharpest image of total loss.</p>",
        "6": "<p><strong>Vayetze mi-bat-Tziyyon kol-hadarah</strong> -- 'And gone from Daughter Zion is all her majesty.' <em>Hadar</em> (H1926, majesty/splendor/honor) -- the royal dignity and sacred glory associated with Jerusalem and the Temple. Its departure is the inverse of the <em>kavod YHWH</em> (glory of YHWH) departing the Temple in Ezekiel 10-11. <em>Hayu sareha ke-ayalim lo matzeu mirheh</em> -- 'her princes have become like deer that find no pasture.' The simile: deer (<em>ayalim</em>) without pasture are desperate, directionless, and doomed. Princes who should lead are now like animals fleeing a wasteland. <em>Vayelekhu velo-koach lifnei rodeif</em> -- 'and they fled without strength before the pursuer.' The exhaustion of total defeat.</p>",
        "7": "<p><strong>Zakhrah Yerushalayim yemei onyah u-merudeha</strong> -- 'Jerusalem remembers in the days of her affliction and her wandering.' <em>Zekhirah</em> (H2142, to remember) -- memory is both gift and torment: she remembers what she has lost. <em>Kol machamudeha asher hayu mi-yemei qedem</em> -- 'all the precious things she had from days of old.' <em>Machmudim</em> (H4261, precious/desirable things) -- the Temple treasures, the liturgy, the peace. <em>Bi-nefol ammah be-yad tzar ve-ein ozer lah</em> -- 'when her people fell into the hand of the enemy and there was no helper.' <em>Ozer</em> (H5826, helper) -- another dimension of the abandoned woman; she cries out and no one answers. <em>Rauha tzarim sachaku al-mishbateyha</em> -- 'the enemies looked on her and mocked at her downfall.' The public shame of defeated Jerusalem witnessed by her captors.</p>",
        "8": "<p><strong>Chet chatah Yerushalayim</strong> -- 'Jerusalem has sinned greatly.' The doubled construction (cognate accusative) intensifies: she has sinned a sin, she has grossly transgressed. <em>Al-ken le-nidah hayetah</em> -- 'therefore she has become an object of abhorrence.' <em>Niddah</em> (H5079, menstrual impurity/thing to be put away) -- the ritual category of separation. Jerusalem's sin has rendered her ritually impure and therefore socially excluded, the opposite of the holy city at the center of the nations. <em>Kol-mechabbedehah hizziluha</em> -- 'all who honored her despise her, for they have seen her nakedness.' The reversal: those who gave honor now give contempt. <em>Ervah</em> (H6172, nakedness) -- exposure and shame; also the legal language of sexual scandal and covenant violation (Deut 24:1).</p>",
        "9": "<p><strong>Tumah be-shulehah</strong> -- 'Her uncleanness was in her skirts.' <em>Tumah</em> (H2932, impurity/uncleanness) -- ceremonial defilement. The metaphor of pollution in the hem of the garment represents the accumulation of sin that had become visible but unaddressed. <em>Lo zakhrah acharitah</em> -- 'she did not consider her end.' <em>Acharit</em> (H319, end/latter part/outcome) -- the same word Proverbs uses for wisdom's foresight: the fool does not consider how things will end. Jerusalem lacked the wisdom to foresee the consequences of covenant violation. <em>Vattered plaim ein menachem lah</em> -- 'she has fallen terribly; there is no one to comfort her.' The second <em>menachem</em> refrain. <em>Reh YHWH et-onyah</em> -- 'Look, O YHWH, at my affliction!' The first direct address to YHWH, breaking from third-person description to first-person appeal.</p>",
        "10": "<p><strong>Yado parash tzar</strong> -- 'The enemy spread out his hand.' <em>Parash yad</em> (to spread the hand) -- the gesture of plundering; the enemy's hand extended over Jerusalem's treasuries. <em>Al kol-machamudeha</em> -- 'over all her precious things.' The <em>machmudim</em> return from v.7 -- Temple vessels, sacred objects, royal treasuries -- all now handled by the enemy's plundering hand. <em>Ki ratah goyim bau mikdashah</em> -- 'for she saw the nations enter her sanctuary.' The ultimate desecration: Gentiles entering the qodesh (holy place) that was forbidden even to many Israelites. <em>Asher tzivvitah lo-yavou vaqahal lakh</em> -- 'those whom you commanded not to enter your assembly.' The Torah's exclusion of certain nations from the assembly (Deut 23:2-9) has been violated by the very fact of conquest.</p>",
        "11": "<p><strong>Kol-ammah neenaichim</strong> -- 'All her people groan.' <em>Neanom</em> (H584, to sigh/groan) -- the sound of desperate need, the moan that precedes prayer. <em>Mevaqshim lachem</em> -- 'seeking bread.' The famine that accompanied the siege (2 Kings 25:3; Jer 52:6) -- the most basic human need unmet. <em>Natenu machamudehem be-okhel le-hashiv nafesh</em> -- 'they give their precious things for food to revive their strength.' The <em>machmudim</em> (precious things) appear a third time -- now traded for survival food. What was sacred becomes mere barter. <em>Re eh YHWH ve-habbitah ki hayiti zelulaah</em> -- 'Look, O YHWH, and see, for I have become worthless.' The second direct address to YHWH -- the cry intensifies.</p>",
        "12": "<p><strong>Lo aleikhem kol-ovrei derekh</strong> -- 'Is it nothing to you, all you who pass by?' The most famous verse in Lamentations. The Hebrew <em>lo aleikhem</em> (not to you) is literally: 'nothing to you?' -- a challenge to the indifferent passerby. Jerusalem appeals to witnesses. <em>Habitu u-reu im-yesh makhov ke-makhovi asher olal li</em> -- 'Look and see if there is any sorrow like my sorrow, which was brought upon me.' <em>Makhov</em> (H4341, pain/sorrow) -- the word for grief that goes to the depths of one's being. The claim is that Jerusalem's suffering is unique in its severity. <em>Asher hoga YHWH be-yom charon appo</em> -- 'which YHWH inflicted on the day of his fierce anger.' The divine agency is again named; the suffering is not random but the result of YHWH's furious, purposeful action.</p>",
        "13": "<p><strong>Mi-marom shalach-esh be-atzmotai</strong> -- 'From on high he sent fire into my bones.' The divine fire is not metaphorical -- it describes the destruction's violence reaching into the marrow of Jerusalem's life. <em>Atzmot</em> (bones) -- frequently used for the essential core of one's being (Ps 6:3; 31:11; Ezek 37). The fire from above (YHWH) burned downward into the inmost structure of the city and people. <em>Vayirdenah</em> -- 'and it subdued them.' <em>Peras reshet le-raglai</em> -- 'He spread a net for my feet.' The net imagery (H7568) -- used of hunters trapping prey; YHWH as the one who set the trap for Jerusalem's escape. <em>Heshipani achoranit</em> -- 'he turned me back.' <em>Natani shomemah kol-hayom dava</em> -- 'he has made me desolate and faint all the day long.'</p>",
        "14": "<p><strong>Nishqad ol pashai be-yado</strong> -- 'The yoke of my transgressions was bound.' <em>Nishqad</em> (to bind tightly/to be wakeful over) -- an unusual verb suggesting careful, deliberate binding. <em>Pesha</em> (H6588, transgression) -- the same strong covenant-violation term as v.5. The transgressions are not loose moral failures but a yoke -- <em>ol</em> (H5923) -- bound onto Jerusalem's neck by YHWH's own hand. <em>Yishtargu alu al-tzavvari</em> -- 'they are woven together; they go up upon my neck.' The intertwining of the sins into a yoke suggests their accumulated, integrated character -- not isolated acts but a pattern of covenant violation. <em>Hikhshil kochi</em> -- 'he has made my strength fail.' The inevitable result of bearing the yoke of judgment.</p>",
        "15": "<p><strong>Sillah kol-abirai YHWH be-kirbi</strong> -- 'The Lord rejected all my mighty men in my midst.' <em>Sillah</em> (H5541, to set aside/toss away) -- a contemptuous discarding. The military strength of Jerusalem -- its elite warriors -- was cast aside by YHWH as ineffective. <em>Qara alai moed</em> -- 'he summoned an assembly against me.' The tragic irony: <em>moed</em> normally denotes the sacred festival assembly of worship; here YHWH calls a moed against Jerusalem -- a military assembly of destruction rather than a liturgical assembly of praise. <em>Lishbor bachurai</em> -- 'to crush my young men.' The youth who should have been the future were crushed. <em>Gat darak YHWH le-vetulat bat-Yehudah</em> -- 'The Lord has trodden the virgin Daughter Judah as in a winepress.' The winepress image (<em>gat</em>) -- harvest fruit crushed underfoot -- applied to the people of Judah. A reversal of vineyard imagery from Isaiah.</p>",
        "16": "<p><strong>Al-elleh ani vokhiyah</strong> -- 'For these things I weep.' The first-person voice of the personified city intensifies. <em>Eini eini yeredah mayim</em> -- 'my eye, my eye runs down with water.' The doubled <em>eini</em> emphasizes the uncontrollable flow of tears. <em>Ki rachaq mimmenni menachem</em> -- 'because far from me is the comforter.' The third <em>menachem</em> refrain -- but now the comforter's absence is described spatially: <em>rachaq</em> (far, distant). The one who should be near is unreachably far. <em>Meshiv nafshi</em> -- the comforter who would 'restore my soul' (same phrase as Ps 23:3 -- YHWH the shepherd restoring his flock). <em>Hayu vanai shomemim ki gavar ha-oyev</em> -- 'my children are desolate because the enemy has prevailed.'</p>",
        "17": "<p><strong>Pershah Tziyyon et-yadehah ein menachem lah</strong> -- 'Zion spreads out her hands; there is no comforter for her.' The fourth and climactic <em>menachem</em> refrain in ch 1. <em>Pershah yadehah</em> -- the gesture of prayer and petition, hands spread upward or outward in appeal. But the hands reach into emptiness; no comforter responds. <em>Tzivvah YHWH le-Yaaqov sevivav tzarav</em> -- 'YHWH has commanded Jacob's neighbors to be his enemies.' The theological weight: YHWH himself commanded the surrounding nations to become adversaries. The enemies are instruments of divine judgment, not autonomous aggressors. <em>Hayetah Yerushalayim le-niddah beinetam</em> -- 'Jerusalem has become an unclean thing among them.' The <em>niddah</em> exclusion of v.8 returns -- Jerusalem is quarantined from the community of nations by her ritual defilement of sin.</p>",
        "18": "<p><strong>Tzaddiq hu YHWH</strong> -- 'The LORD is righteous.' In the middle of the lament, the city acknowledges divine justice: the destruction is not unjust. <em>Ki fi mariti</em> -- 'for I rebelled against his word.' <em>Mariti</em> (H4784, to rebel/be contentious) -- the admission of covenant rebellion. This verse is the theological hinge of ch 1: Jerusalem's theological confession within the lament. She does not protest her innocence but admits her guilt. <em>Shimu-na kol-ha-ammim ve-reu makhovi</em> -- 'Hear, all peoples, and behold my sorrow.' The appeal to witness expands beyond passersby (v.12) to all nations. <em>Betulotai u-vachurei halekhu vashevi</em> -- 'my young women and young men have gone into captivity.' The youth -- the future -- in exile.</p>",
        "19": "<p><strong>Qarati le-meahavai hemah rimmuni</strong> -- 'I called to my lovers; they deceived me.' <em>Rimmuni</em> (H7411, deceived/betrayed) -- the political allies who promised security have proved false. <em>Kohanai u-zeqenai ba-ir gave u</em> -- 'my priests and elders perished in the city.' Those who were meant to intercede (priests) and to counsel (elders) are dead. The institutional leadership has collapsed. <em>Ki viqqeshu okhel lamo ve-yashivu et-nafesham</em> -- 'while they sought food to revive their strength.' Even the priests died in the siege-famine, searching for bread like everyone else. The liturgical community that sustained the nation's covenant life has dissolved.</p>",
        "20": "<p><strong>Reh YHWH ki tzar li</strong> -- 'Look, O YHWH, for I am in distress.' The third direct address to YHWH. <em>Tzar</em> (H6862, narrow/distress) -- the same root as <em>metzarim</em> (v.3) -- constriction, the opposite of the spaciousness of covenant blessing. <em>Meai chamaru</em> -- 'my stomach churns.' <em>Chamaru</em> (H2560, to ferment/churn) -- the internal upheaval of grief and fear. <em>Nefekh libbi alai</em> -- 'my heart is overturned within me.' <em>Nafakh</em> (to be overturned/poured out) -- the dissolution of inner structure. <em>Ki marod mariti</em> -- 'for I have been very rebellious.' The repeated confession: twice in this chapter Jerusalem names her own rebellion as the cause. <em>Mi-chutz shikhkhelah cherev ba-bayit ka-mavet</em> -- 'Outside, the sword bereaves; inside, it is like death.' The siege has made outside and inside equally fatal.</p>",
        "21": "<p><strong>Shamu ki neenaichti</strong> -- 'They heard how I am groaning.' <em>Neanaichti</em> (H584, I am groaning) -- the groan as both audible suffering and implicit prayer. <em>Ein menachem li</em> -- the fifth and final <em>menachem</em> refrain of ch 1. The entire first chapter is structured around this absence: the comforter who does not come. <em>Kol-oyvai shameu raati sasu</em> -- 'all my enemies heard of my trouble; they rejoiced.' <em>Sasu</em> (rejoiced/exulted) -- the enemy's delight at Jerusalem's fall, which will itself become a subject of lamentation and judgment. <em>Heveita yom-qarata</em> -- 'You brought on the day you announced.' The enemies' joy is within YHWH's announced plan.</p>",
        "22": "<p><strong>Tavo kol-raatam lefanekha</strong> -- 'Let all their evil come before you.' The lament turns to imprecation -- a prayer for YHWH to deal with the enemies as he has dealt with Jerusalem. <em>Ve-olel lamo ka-asher olalta li</em> -- 'and deal with them as you have dealt with me for all my transgressions.' The final verse requests proportionate divine justice: the enemies, who have also transgressed, should face the same judgment Jerusalem has faced. <em>Ki rabbim anachoti ve-libbi davvai</em> -- 'for my groans are many and my heart is faint.' The book's first chapter ends not with resolution but with ongoing grief: the groaning continues, the heart remains sick. The lack of comforter with which the chapter opened is matched by the lack of comfort with which it closes -- an unresolved lament awaiting divine response.</p>"
    },
    "2": {
        "1": "<p><strong>Eikhah yaib Adonai be-appo</strong> -- 'How the Lord has covered Daughter Zion with his anger.' Ch 2 opens with the same <em>eikhah</em> as ch 1, but the perspective shifts dramatically: where ch 1 described the suffering primarily from Jerusalem's perspective, ch 2 focuses on YHWH as the active agent of destruction. <em>Yaib</em> (H5743, to cover with clouds/darken) -- YHWH's anger is like a storm cloud covering the city. <em>Hishlik mi-shamayim eretz tiferet Yisrael</em> -- 'he cast down from heaven to earth the splendor of Israel.' The <em>tiferet</em> (glory/beauty/splendor) of Israel -- likely the Temple and its associated glory -- is hurled downward. The fall is literally from heaven to earth, a reversal of the Temple's sacred orientation. <em>Ve-lo zakhar hadom raglav be-yom appo</em> -- 'and did not remember his footstool on the day of his anger.' The footstool (<em>hadom raglav</em>) of YHWH is the Temple (Ps 99:5; 132:7; 1 Chr 28:2) -- the place of his earthly throne-presence, now forgotten in wrath.</p>",
        "2": "<p><strong>Billa YHWH ve-lo chamal</strong> -- 'The Lord swallowed up without mercy.' <em>Billa</em> (H1104, to swallow up/engulf) -- the verb of total destruction; nothing remains after swallowing. <em>Lo chamal</em> (he did not spare/had no mercy) -- the absence of the compassion (<em>rachamim</em>) that normally characterizes YHWH. <em>Et kol-neot Yaaqov</em> -- 'all the dwelling places of Jacob.' <em>Neot</em> (H4999, pastures/dwelling places) -- the inhabited land of the covenant people. <em>Haras be-evrato mivtzarei bat-Yehudah</em> -- 'he broke down in his wrath the strongholds of Daughter Judah.' <em>Haras</em> (H2040, to tear down/demolish) -- the military destruction of fortifications. The word appears repeatedly in this chapter. <em>Higa la-aretz chilelah mamlakhtah ve-sareha</em> -- 'he has brought down to the ground in dishonor the kingdom and its princes.' The royal institutions have been brought low.</p>",
        "3": "<p><strong>Gada be-charon af kol-qeren Yisrael</strong> -- 'He cut off in fierce anger all the strength of Israel.' <em>Gada</em> (H1438, to cut off/fell) -- the verb for cutting down a tree; Israel's military strength is felled like timber. <em>Qeren</em> (H7161, horn) -- the symbol of power and strength; all of Israel's strength is cut at once. <em>Heishiv achor yemino mifnei oyev</em> -- 'he withdrew his right hand from before the enemy.' The <em>yamin</em> (right hand) is YHWH's weapon hand, his hand of saving power. Its withdrawal is the decisive moment: YHWH stops fighting for Israel and begins fighting against them. <em>Vayivar be-Yaaqov ke-esh lehevah</em> -- 'and he burned through Jacob like a flaming fire.' The divine fire imagery from ch 1:13 recurs -- but now the source (YHWH himself burning like a flame) is fully explicit.</p>",
        "4": "<p><strong>Darakh qashto ke-oyev</strong> -- 'He bent his bow like an enemy.' The theological crisis of ch 2 reaches its apex: YHWH acts as <em>oyev</em> (enemy) against his own people. <em>Nitzav yemino ke-tzar</em> -- 'he set his right hand like a foe.' The same right hand that was Israel's salvation (Exod 15:6; Ps 118:15-16) is now set as an adversary. <em>Va-yaharog kol machmadei ayin</em> -- 'and he killed all who were precious to the eye.' <em>Machmadim</em> (precious things/beloved ones) -- the recurring word now for people rather than objects: the beloved ones whom YHWH himself slew. <em>Be-ohel bat-Tziyyon shafakh ke-esh chamato</em> -- 'in the tent of Daughter Zion he poured out his wrath like fire.' YHWH is not merely permitting the enemy's destruction but actively pouring out fury within the sacred precincts.</p>",
        "5": "<p><strong>Hayah YHWH ke-oyev</strong> -- 'The LORD has become like an enemy.' The starkest theological statement in the book. <em>Ke-oyev</em> (like an enemy) -- the particle <em>ke</em> (like) is important: YHWH is compared to an enemy in his actions, not identified as one essentially. But the functional equivalence is real and devastating. <em>Billa Yisrael</em> -- 'he swallowed up Israel.' The <em>billa</em> of v.2 returns. <em>Billa kol-armenotehah</em> -- 'he swallowed up all her palaces.' <em>Armenotot</em> (H759, palaces/citadels) -- the structures of royalty and governance consumed. <em>Ve-yarbeh be-bat-Yehudah taaniyah va-aniyah</em> -- 'and he has multiplied mourning and lamentation in Daughter Judah.' <em>Taaniyah</em> (H8589, lamentation) and <em>aniyah</em> (H592, sighing/groaning) -- a pair of mourning terms.</p>",
        "6": "<p><strong>Vayachmos ke-gan sukko</strong> -- 'He has stripped his booth like a garden.' <em>Sukko</em> (his booth/shelter) refers to the Temple as YHWH's dwelling place -- the same vocabulary as Ps 27:5 and 76:3. The garden stripping suggests violent clearance. <em>Shichet moado</em> -- 'he has destroyed his meeting place.' <em>Moed</em> again -- the appointed-feast assembly, but now it is YHWH who destroys his own meeting place. <em>Hishkach YHWH be-Tziyyon moed ve-Shabbat</em> -- 'YHWH has caused Zion to forget the appointed feast and the Sabbath.' <em>Hishkach</em> (to cause to forget) -- YHWH himself erases the liturgical calendar, the rhythm of covenant worship. The Sabbath and festival cycle that structured Israel's life is suspended. <em>Vayinatz be-zaam appo melekh ve-kohen</em> -- 'and in his angry indignation he has spurned king and priest.' Both the royal and priestly institutions are objects of divine contempt.</p>",
        "7": "<p><strong>Zanach YHWH mizbecho</strong> -- 'The Lord has rejected his altar.' <em>Zanach</em> (H2186, to reject/cast off) -- a strong term for absolute repudiation; the same verb used in Ps 77:8 for the fear that YHWH has forever cast off. The altar -- the central locus of Israel's sacrificial worship and atonement -- is rejected by the one to whom it was directed. <em>Nir miqdash</em> -- 'he has disowned his sanctuary.' <em>Nir</em> (H5010, to abhor/disown) -- the complete reversal of the Temple's consecration. <em>Higger be-yad oyev chomat armenotehah</em> -- 'he has delivered into the hand of the enemy the walls of her palaces.' What the covenant was meant to protect has been handed over to the very enemy it was meant to exclude. <em>Qol natenu be-veit-YHWH ke-yom moed</em> -- 'they raised a shout in the house of the LORD as on the day of appointed feast.' The enemy's battle cry in the Temple sounds like a feast-day shout -- a terrible inversion of sacred sound.</p>",
        "8": "<p><strong>Chashav YHWH le-hashchit chomat bat-Tziyyon</strong> -- 'The LORD determined to lay in ruins the wall of Daughter Zion.' <em>Chashav</em> (H2803, to plan/design/reckon) -- the same word used for skilled craftsmanship (Exod 31:4) and for theological recounting; here it is YHWH's deliberate architectural plan -- but for demolition. <em>Natah qav lo-heishiv yado mi-balla</em> -- 'he stretched out the measuring line; he did not restrain his hand from swallowing.' The <em>qav</em> (measuring line) is the builder's tool -- but here stretched out by a divine demolisher measuring what he will destroy (cf. Amos 7:7-9, the plumb line). <em>Va-yaavel chel ve-chomah</em> -- 'and he made rampart and wall mourn.' Even the fortification structures participate in the lament.</p>",
        "9": "<p><strong>Tabeu va-aretz sharehah</strong> -- 'Her gates have sunk into the ground.' The gates -- the place of justice, commerce, and assembly -- are not merely broken but have sunk below the surface, the inverse of the city built on a hill. <em>Ibad u-shiver berichehah</em> -- 'he has destroyed and broken her bars.' The bars (<em>berichin</em>) that locked the gates for defense are shattered. <em>Malkah ve-sareha baggoyim ein Torah</em> -- 'her king and princes are among the nations; the Torah is no more.' The two institutions of covenant governance -- king and Torah -- are simultaneously lost: the king in exile, the Torah without teacher or Temple context to enact it. <em>Gam-neviehah lo matzeu chazon me-YHWH</em> -- 'also her prophets find no vision from YHWH.' The prophetic word has ceased -- the silence of YHWH is itself a form of judgment.</p>",
        "10": "<p><strong>Yeshvu la-aretz yidmemu ziqnei bat-Tziyyon</strong> -- 'The elders of Daughter Zion sit on the ground in silence.' <em>Yidmemu</em> (H1826, to be silent/still/dumb) -- the silence that is the absence of wisdom's speech. The elders, whose role was counsel and judgment at the gate, sit mute in the dust. <em>Alu afar al-rosham</em> -- 'they have thrown dust on their heads.' The gesture of mourning: dust or ashes on the head (Josh 7:6; Job 2:12; Neh 9:1). <em>Chatru saqim betulot Yerushalayim</em> -- 'the virgins of Jerusalem have bowed their heads to the ground.' <em>Chatru</em> (bowed down/girded in sackcloth) -- the double gesture of grief: posture and garment. The book's most vulnerable figures -- the young women who represent future and fertility -- are prostrated in mourning.</p>",
        "11": "<p><strong>Kalu ve-demaot einai</strong> -- 'My eyes are spent with weeping.' <em>Kalu</em> (H3615, to be spent/exhausted/completed) -- the eyes have reached their limit of tears. The observer's own weeping begins now, shifting from third-person description to first-person participation in the grief. <em>Chamarmaru meai</em> -- 'my stomach churns.' The same <em>chamarmaru</em> as 1:20 -- the physical manifestation of grief in the gut. <em>Nishpakh la-aretz kevodi</em> -- 'my bile is poured on the ground.' <em>Kaved</em> (liver/bile, H3516) -- the ancients considered the liver the seat of emotion; its pouring out = total emotional depletion. <em>Al-shever bat-ammi</em> -- 'because of the destruction of Daughter my-people.' <em>Shever</em> (H7667, breaking/destruction) -- a decisive breaking. The phrase <em>bat-ammi</em> (Daughter of my people) expresses intimate identification: not merely 'the people' but 'my people's daughter.'</p>",
        "12": "<p><strong>Le-imotam yomeru ayeh dagan va-yayin</strong> -- 'They cry to their mothers: Where is bread and wine?' The particular horror of famine during siege: children crying for basic food. <em>Dagan</em> (grain/bread) and <em>yayin</em> (wine) -- the staples of covenant blessing (Deut 7:13; 11:14). Their absence represents the inversion of covenant promise. <em>Be-hithatpam ke-chalal bi-rechovot ha-ir</em> -- 'as they faint like the wounded in the streets of the city.' <em>Chalal</em> (H2491, wounded/slain) -- the children's fainting from hunger is compared to warriors fallen in battle. The domestic space of the city has become a battlefield. <em>Be-hishta-peak nafesham el-cheq imotam</em> -- 'as their soul is poured out into their mothers' bosoms.' The dying children collapse onto their mothers -- an image of total helplessness combined with the final refuge of maternal embrace.</p>",
        "13": "<p><strong>Mah-aidekh mah-adammeh lakh ha-betulat bat-Tziyyon</strong> -- 'What can I bear witness against you? What can I compare to you, O virgin Daughter Zion?' The observer's question is not rhetorical mockery but genuine perplexity: there is no adequate comparison for this suffering. <em>Ki-gadol ka-yam shivrekh</em> -- 'for great as the sea is your ruin.' <em>Shever</em> (breaking/destruction, H7667) -- the same word as v.11. The comparison to the sea (<em>yam</em>) -- limitless, unmeasurable -- indicates that the catastrophe exceeds normal frameworks of comparison. <em>Mi-yirpa lakh</em> -- 'who can heal you?' <em>Rafa</em> (H7495, to heal) -- healing is the word of covenant restoration; but who can heal a wound of ocean dimensions?</p>",
        "14": "<p><strong>Neviayikh chazu lakh shav va-tafel</strong> -- 'Your prophets have seen for you false and deceptive visions.' <em>Shav</em> (H7723, emptiness/falsehood/vanity) -- the same word used in the third commandment ('do not take the name of YHWH in vain' / <em>la-shav</em>); prophets who spoke in YHWH's name without divine authority. <em>Tafel</em> (H8602, insipid/daubed/whitewashed) -- false prophecy as whitewashing over cracks, giving a false impression of structural soundness. <em>Ve-lo gilu al-avonekh le-hashiv shevutekh</em> -- 'they did not expose your iniquity to restore your fortune.' True prophecy addresses sin in order to enable restoration; false prophecy avoids it and leaves the people without warning or opportunity for repentance. <em>Vayechezu lakh massaot shav u-maduchim</em> -- 'they saw false oracles and causes of banishment for you.' The false prophets' visions contributed to the exile they were supposed to prevent.</p>",
        "15": "<p><strong>Sapequ alayikh kappayim kol-ovrei derekh</strong> -- 'All who pass by clap their hands at you.' Where 1:12 appealed to passers-by for sympathy, here the passers-by respond with mockery -- clapping hands (<em>sapequ kappayim</em>) as a gesture of contempt and derision. <em>Sharqu vayanu rosham al bat-Yerushalayim</em> -- 'they hiss and wag their heads at Daughter Jerusalem.' <em>Sharqu</em> (to hiss) -- a sound of scorn and shock. <em>Hazot ha-ir asher yomeru kelilat yofi</em> -- 'Is this the city that was called the perfection of beauty?' The quotation mocks the theological claim of Jerusalem's unique beauty (Ps 48:2 -- 'beautiful in elevation, the joy of all the earth'). What was acclaimed as perfect has been reduced to ruin. <em>Mesos le-khol-ha-aretz</em> -- 'the joy of all the earth' -- now an object of scorn rather than joy.</p>",
        "16": "<p><strong>Patztu alayikh pihhem kol-oyvayikh</strong> -- 'All your enemies open their mouths against you.' <em>Patztu pihhem</em> (opened their mouth wide) -- the gaping mouth of contempt and triumph. <em>Sharqu va-yachrequ shen</em> -- 'they hiss and gnash their teeth.' <em>Charaqu shen</em> (gnashing teeth) -- the aggressive physical expression of hostility and derision (Ps 35:16; 37:12). <em>Amru bilanu</em> -- 'they say: We have swallowed her up.' The same <em>bila</em> verb used of YHWH's action in vv. 2, 5 -- now the enemies claim the same act as their own. <em>Akh zeh ha-yom shequivvinu</em> -- 'surely this is the day we looked for.' The enemies' long-anticipated opportunity has arrived. <em>Matzanu rainu</em> -- 'we found it; we saw it.' The gleeful confirmation of Jerusalem's destruction.</p>",
        "17": "<p><strong>Asah YHWH asher zamam</strong> -- 'The LORD has done what he purposed.' <em>Zamam</em> (H2161, to plan/devise/purpose) -- YHWH's deliberate intention; nothing has happened accidentally. <em>Bitza imrato asher tzivvah mi-mei qedem</em> -- 'he has carried out his word that he commanded long ago.' The destruction is the execution of the covenant curses announced in Leviticus 26 and Deuteronomy 28 -- commands given at Sinai, centuries before their fulfillment. <em>Haras ve-lo chamal</em> -- 'he tore down without mercy.' The same <em>lo chamal</em> of v.2. <em>Vayesamach alayikh oyev</em> -- 'and he caused the enemy to rejoice over you.' YHWH is the cause even of the enemy's rejoicing -- a further dimension of the theological crisis. <em>Herim qeren tzarayikh</em> -- 'he exalted the horn of your adversaries.' The horn (power) that was supposed to belong to Israel (Ps 89:17) has been transferred to the enemy.</p>",
        "18": "<p><strong>Tzaaq libam el-YHWH</strong> -- 'Their heart cried to the LORD.' Suddenly a call to prayer emerges. <em>Chomat bat-Tziyyon</em> -- 'O wall of Daughter Zion.' The wall itself is addressed as a mourner and intercessor. <em>Horidi ka-nachal dimah yomam va-lailah</em> -- 'let tears stream down like a river day and night.' <em>Ka-nachal</em> (like a wadi/stream) -- the image of tears as a never-stopping watercourse. Day and night (<em>yomam va-lailah</em>) -- total, unceasing lament. <em>Al-titni fugat lakh</em> -- 'give yourself no rest.' <em>Fugat</em> (H6314, respite/rest) -- the call to relentless prayer. <em>Al-tidom bat-einekh</em> -- 'let not your eye's daughter be still.' The 'daughter of your eye' -- the pupil -- should not stop weeping. The intensity of the call matches the severity of the crisis.</p>",
        "19": "<p><strong>Qumi roni va-layl</strong> -- 'Arise, cry out in the night.' The call to night-prayer -- the watches of the night when grief is most acute and the cry most desperate. <em>Le-rosh ashmurot</em> -- 'at the beginning of the night watches.' The night was divided into three or four watches; the first watch (beginning of the night) is when prayer should begin, not wait. <em>Shiphki ka-mayim libbekh nochach penei YHWH</em> -- 'pour out your heart like water before the presence of the LORD.' <em>Shaphak lev</em> (to pour out the heart) -- total self-disclosure in prayer, holding nothing back. <em>Nochach penei YHWH</em> -- 'before the face of YHWH' -- the prayer is directed at the divine presence. <em>Sei elav kappayikh</em> -- 'lift your hands to him.' The gesture of prayer -- lifted palms. <em>Al-nefesh olalelayikh</em> -- 'for the souls of your young children who are fainting with hunger at every street corner.'</p>",
        "20": "<p><strong>Reh YHWH ve-habbitah le-mi olalta koh</strong> -- 'Look, O LORD, and see! With whom have you dealt thus?' The direct appeal to divine witness. <em>Habbitah</em> (H5027, to look/gaze with attention) -- to look carefully, not casually. The question <em>le-mi olalta koh</em> (to whom have you done thus) is not a challenge to divine justice but a cry of bewilderment: this is your covenant people -- this is what has happened. <em>Im-tokhal nashim piryam</em> -- 'Should women eat the fruit of their womb?' The horror of cannibalism during the siege is introduced (cf. Deut 28:53-57; Jer 19:9; Ezek 5:10) -- the most extreme symbol of total social collapse. <em>Im-yehareg be-miqdash YHWH kohen ve-navi</em> -- 'should priest and prophet be killed in the sanctuary of the LORD?' The Temple, the last refuge, has become a killing floor.</p>",
        "21": "<p><strong>Shakhvu la-aretz chutztot naar ve-zaqen</strong> -- 'In the dust of the streets lie young and old.' The dead lie unburied -- the extremity of desolation. <em>Betulotai u-vachuray naflu ve-charev</em> -- 'my young women and young men have fallen by the sword.' The young generation -- the future -- is slain. <em>Haragtah be-yom appekha tavachta lo chamaltha</em> -- 'you killed them in the day of your anger; you slaughtered without mercy.' The theological claim remains: YHWH is the agent. <em>Tavachta</em> (H2873, to slaughter/butcher) -- the vocabulary of the slaughterhouse applied to the divine action. <em>Lo chamaltha</em> -- the <em>lo chamal</em> of vv. 2, 17 -- three times in this chapter the absence of divine mercy is named. The covenant compassion (<em>rachamim</em>) has been suspended.</p>",
        "22": "<p><strong>Tiqra ke-yom moed megorai mi-saviv</strong> -- 'You summoned as on a day of appointed feast my terrors from every side.' The final verse uses the <em>moed</em> motif one last time -- but reversed. YHWH calls together ('summons' like a festival assembly) Jerusalem's terrors (<em>megorai</em>, H4032, terrors/fears) from every direction. The feast-day convocation is now a gathering of horrors. <em>Ve-lo hayah be-yom af-YHWH palith ve-sarid</em> -- 'and on the day of the LORD's anger no one escaped or survived.' The totality of destruction -- <em>palith</em> (escapee) and <em>sarid</em> (survivor/remnant) -- both categories are emptied. <em>Asher tiladti ve-ribbiti</em> -- 'those whom I carried and raised.' The personified Jerusalem speaks as a mother whose children were her investment; they are all gone. Chapter 2 ends with no resolution, no comfort, no reversal -- only the enormity of what YHWH has done to his people standing naked before the reader.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'lamentations')
    merge_comm(existing, LAMENTATIONS)
    save_comm('mkt-original', 'lamentations', existing)
    print('Lamentations 1-2 mkt-original written.')

if __name__ == '__main__':
    main()
